/**
 * Memory Form Button Wrapper - Embed Bundle
 * 
 * Uses your actual Webflow Memory Form Button component
 * Auto-initializes on any element with [data-memory-button] attribute
 */

import { mountMemoryFormButtonWrapper } from './MemoryFormButtonWrapper';

// Export for manual initialization
export { mountMemoryFormButtonWrapper };

// Variant type for validation
type ButtonVariant = 
  | "Warm Sandston"
  | "Warm Sandston Outline" 
  | "Slate Navy"
  | "Slate Navy Outline"
  | "Ocean Teal"
  | "Ocean Teal Outline"
  | "Rustwood Red"
  | "Rustwood Outline";

// Auto-initialize any [data-memory-button] elements on page load
if (typeof window !== 'undefined') {
  function initMemoryButtons() {
    const elements = document.querySelectorAll('[data-memory-button]');
    
    elements.forEach((element) => {
      // Skip if already initialized
      if (element.hasAttribute('data-memory-button-initialized')) {
        return;
      }
      
      // Mark as initialized
      element.setAttribute('data-memory-button-initialized', 'true');
      
      // Parse props from data attributes
      const variantAttr = element.getAttribute('data-button-variant') || 'Slate Navy';
      
      // IMPORTANT: Read collection ID from data attribute
      // This is the collection ID that will be used for CMS submissions
      const collectionId = element.getAttribute('data-collection-id');
      
      if (!collectionId) {
        console.error('❌ Memory Form Error: data-collection-id attribute is required on [data-memory-button] element');
        return;
      }
      
      const props = {
        buttonText: element.getAttribute('data-button-text') || 'Post a Memory',
        variant: variantAttr as ButtonVariant,
        collectionId: collectionId, // Pass the collection ID to the component
        itemId: element.getAttribute('data-item-id') || undefined
      };
      
      console.log('🔧 Initializing Memory Form Button with collectionId:', collectionId);
      
      // Mount the component
      try {
        mountMemoryFormButtonWrapper(element as HTMLElement, props);
      } catch (error) {
        console.error('Failed to mount Memory Form Button:', error);
      }
    });
  }
  
  // Initialize on DOM ready
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initMemoryButtons);
  } else {
    initMemoryButtons();
  }
  
  // Re-initialize on dynamic content changes (e.g., Webflow interactions)
  const observer = new MutationObserver((mutations) => {
    let shouldInit = false;
    
    mutations.forEach((mutation) => {
      if (mutation.addedNodes.length > 0) {
        mutation.addedNodes.forEach((node) => {
          if (node instanceof HTMLElement) {
            if (node.hasAttribute('data-memory-button') || 
                node.querySelector('[data-memory-button]')) {
              shouldInit = true;
            }
          }
        });
      }
    });
    
    if (shouldInit) {
      initMemoryButtons();
    }
  });
  
  observer.observe(document.body, {
    childList: true,
    subtree: true
  });
  
  // Make mount function available globally for manual use
  (window as any).mountMemoryFormButtonWrapper = mountMemoryFormButtonWrapper;
}

export default mountMemoryFormButtonWrapper;
